#nullable enable // autogenerated

using MVZ2.Vanilla.Entities;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Contraptions
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.ignitable_Trigger)]
    public class IgnitableBehaviour_Trigger : ContraptionTriggerBehaviour
    {
        public IgnitableBehaviour_Trigger(string nsp, string name) : base(nsp, name)
        {
        }
        public override bool CanTrigger(Entity entity)
        {
            return base.CanTrigger(entity) && !IgnitableBehaviour.IsIgnited(entity);
        }
        public override void Trigger(Entity entity)
        {
            base.Trigger(entity);
            IgnitableBehaviour.Ignite(entity);
        }
    }
}
